import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.nio.file.Path;

public class SecurePathTraversal {
    public static void main(String[] args) throws IOException {
        String userInput = "../../../../../etc/passwd"; // User input containing malicious path traversal
        String basePath = "/var/www/data/files/";

        // Sanitize and validate user input before constructing the file path
        Path resolvedPath = Paths.get(basePath).resolve(Paths.get(userInput).normalize());

        if (!resolvedPath.startsWith(Paths.get(basePath))) {
            System.out.println("Invalid file path");
            return;
        }

        File file = resolvedPath.toFile();

        if (file.exists()) {
            byte[] fileContent = Files.readAllBytes(resolvedPath);
            System.out.println(new String(fileContent));
        } else {
            System.out.println("File not found");
        }
    }
}

